struct ActorChatGuard {
    locks: Arc<StdMutex<BTreeSet<u64>>>,
    actor_id: u64,
}

impl Drop for ActorChatGuard {
    fn drop(&mut self) {
        if let Ok(mut locks) = self.locks.lock() {
            locks.remove(&self.actor_id);
        }
    }
}

