#[derive(Clone, Debug, Deserialize, Serialize)]
#[serde(untagged)]
enum JobReward {
    Label(String),
    Details {
        #[serde(default)]
        label: String,
        #[serde(default)]
        orbs: i32,
    },
}

impl JobReward {
    fn label(&self) -> &str {
        match self {
            JobReward::Label(label) => label,
            JobReward::Details { label, .. } => label,
        }
    }

    fn orbs(&self) -> i32 {
        match self {
            JobReward::Label(_) => 0,
            JobReward::Details { orbs, .. } => *orbs,
        }
    }
}

