async fn generated_seed_card_asset(AxumPath(card_file): AxumPath<String>) -> impl IntoResponse {
    if let Some((card_id, content_type)) = generated_seed_card_bitmap_request(&card_file) {
        let path = seed_content_root()
            .join("core/assets/generated/cards")
            .join(&card_file);
        return match fs::read(path) {
            Ok(bytes) => (
                StatusCode::OK,
                [
                    (header::CONTENT_TYPE, content_type),
                    (header::CACHE_CONTROL, "public, max-age=86400"),
                ],
                bytes,
            )
                .into_response(),
            Err(_) => (
                StatusCode::NOT_FOUND,
                format!("missing generated seed card asset {card_id}"),
            )
                .into_response(),
        };
    }

    let Some(card_id) = card_file.strip_suffix(".svg") else {
        return (StatusCode::NOT_FOUND, "unknown seed card").into_response();
    };
    let Some(spec) = seed_card_art_spec(card_id) else {
        return (StatusCode::NOT_FOUND, "unknown seed card").into_response();
    };
    (
        StatusCode::OK,
        [
            (header::CONTENT_TYPE, "image/svg+xml; charset=utf-8"),
            (header::CACHE_CONTROL, "public, max-age=86400"),
        ],
        generated_seed_card_svg(&spec),
    )
        .into_response()
}

fn generated_seed_card_bitmap_request(card_file: &str) -> Option<(&str, &'static str)> {
    let (card_id, content_type) = if let Some(card_id) = card_file.strip_suffix(".webp") {
        (card_id, "image/webp")
    } else if let Some(card_id) = card_file.strip_suffix(".png") {
        (card_id, "image/png")
    } else {
        return None;
    };
    if card_id.is_empty()
        || card_id.len() > 128
        || !card_id
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_'))
    {
        return None;
    }
    if !seed_content()
        .cards
        .iter()
        .any(|card| card.card_id == card_id)
    {
        return None;
    }
    Some((card_id, content_type))
}

async fn generated_avatar_asset(
    State(state): State<AppState>,
    AxumPath(avatar_file): AxumPath<String>,
) -> impl IntoResponse {
    if let Some(actor_id) = avatar_file
        .strip_suffix(".png")
        .and_then(|value| value.parse::<u64>().ok())
    {
        let path = stored_avatar_image_path(&state.generated_asset_dir, actor_id);
        if let Ok(bytes) = fs::read(path) {
            let content_type = stored_avatar_content_type(&state.generated_asset_dir, actor_id);
            return (
                StatusCode::OK,
                [
                    (header::CONTENT_TYPE, content_type),
                    (header::CACHE_CONTROL, "public, max-age=86400".to_string()),
                ],
                bytes,
            )
                .into_response();
        }
        return (
            StatusCode::OK,
            [
                (header::CONTENT_TYPE, "image/svg+xml; charset=utf-8"),
                (header::CACHE_CONTROL, "public, max-age=3600"),
            ],
            generated_avatar_svg(actor_id),
        )
            .into_response();
    }

    let Some(actor_id) = avatar_file
        .strip_suffix(".svg")
        .and_then(|value| value.parse::<u64>().ok())
    else {
        return (StatusCode::NOT_FOUND, "unknown avatar").into_response();
    };
    (
        StatusCode::OK,
        [
            (header::CONTENT_TYPE, "image/svg+xml; charset=utf-8"),
            (header::CACHE_CONTROL, "public, max-age=86400"),
        ],
        generated_avatar_svg(actor_id),
    )
        .into_response()
}

async fn generated_box_asset(
    AxumPath((box_state, box_file)): AxumPath<(String, String)>,
) -> impl IntoResponse {
    let Some(box_id) = box_file.strip_suffix(".svg") else {
        return (StatusCode::NOT_FOUND, "unknown box").into_response();
    };
    let state = match box_state.as_str() {
        "closed" | "opening" | "open" => box_state.as_str(),
        _ => return (StatusCode::NOT_FOUND, "unknown box").into_response(),
    };
    if box_id.is_empty()
        || box_id.len() > 96
        || !box_id
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '-' | '_'))
    {
        return (StatusCode::NOT_FOUND, "unknown box").into_response();
    }
    (
        StatusCode::OK,
        [
            (header::CONTENT_TYPE, "image/svg+xml; charset=utf-8"),
            (header::CACHE_CONTROL, "public, max-age=86400"),
        ],
        generated_box_svg(box_id, state),
    )
        .into_response()
}

